  ('dietitian-moex-11027', 'dietitian', 'dietitian-moex-093-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '肉類中，何種蛋白質成分不易受熱、酸、鹼之影響，但可攪碎使其破壞，或添加酵素將其分解？ 肌動蛋白（actin）  膠原蛋白（collagen）  肌球蛋白（myosin）  彈性硬蛋白（elastin）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "26283d62182b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
